// Get data from NVIDIA — Review & Improve Post
const postText = $('NVIDIA — Review & Improve Post').first().json.choices[0].message.content;

// Get data from Form Trigger
const formData = $('Form Trigger').first().json;

// Get FLUX API response
const apiResponse = $input.first().json;

// Validate FLUX response
if (!apiResponse.success) {
  throw new Error('FLUX API Error: ' + JSON.stringify(apiResponse));
}

if (!apiResponse.image) {
  throw new Error('No image in FLUX response');
}

// Decode base64 to binary
const imageBuffer = Buffer.from(apiResponse.image, 'base64');

if (imageBuffer.length < 100000) {
  throw new Error(`Image too small: ${imageBuffer.length} bytes`);
}

console.log(`✅ Image ready: ${(imageBuffer.length / 1024).toFixed(0)} KB`);

return [{
  json: {
    post_text: postText,
    topic: formData['Topic'] || '',
    goal: formData['Post Goal'] || '',
    audience: formData['Target Audience'] || '',
    tone: formData['Tone'] || ''
  },
  binary: {
    imageData: await this.helpers.prepareBinaryData(
      imageBuffer,
      'linkedin_image.png',
      'image/png'
    )
  }
}];

// Extract upload URL and asset URN from LinkedIn response
const uploadResponse = $input.first().json;

const uploadUrl = uploadResponse.value.uploadMechanism['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest'].uploadUrl;
const assetUrn = uploadResponse.value.asset;

return {
  uploadUrl: uploadUrl,
  assetUrn: assetUrn
};

